namespace sv_00e9b32308dd46098d62d300fb429c8e.Models;

// Submitted DTOs
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(FullName) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone) &&
        !string.IsNullOrWhiteSpace(Address);

    public PersonalInfo ToRecord() => new(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim());
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Company) &&
        !string.IsNullOrWhiteSpace(Title) &&
        StartDate.HasValue;

    public WorkEntry ToRecord() => new(
        Company.Trim(),
        Title.Trim(),
        StartDate!.Value,
        IsCurrent ? null : EndDate,
        Description.Trim());
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Name) &&
        !string.IsNullOrWhiteSpace(Relationship) &&
        !string.IsNullOrWhiteSpace(Email) &&
        !string.IsNullOrWhiteSpace(Phone);

    public Reference ToRecord() => new(Name.Trim(), Relationship.Trim(), Email.Trim(), Phone.Trim());
}

@* Step indicator bar showing progress through the multi-step form *@

<nav class="step-indicator mb-4" aria-label="Application steps">
    <ol class="step-list">
        @for (var i = 0; i < StepNames.Length; i++)
        {
            var step = i + 1;
            var status = GetStepStatus(step);
            <li class="step-item @status" @onclick="() => OnStepClick(step)" role="button" tabindex="0">
                <span class="step-circle">
                    @if (status == "completed")
                    {
                        <span class="step-check">✓</span>
                    }
                    else
                    {
                        @step
                    }
                </span>
                <span class="step-label">@StepNames[i]</span>
            </li>
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public int CompletedUpTo { get; set; }
    [Parameter] public EventCallback<int> OnStepSelected { get; set; }

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (step < CompletedUpTo + 1) return "completed";
        return "future";
    }

    private async Task OnStepClick(int step)
    {
        // Only allow navigating to completed steps
        if (step < CompletedUpTo + 1)
        {
            await OnStepSelected.InvokeAsync(step);
        }
    }
}

.step-indicator {
    width: 100%;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: '';
    position: absolute;
    top: 18px;
    left: 36px;
    right: 36px;
    height: 2px;
    background: #dee2e6;
    z-index: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    z-index: 1;
    flex: 1;
    cursor: default;
}

.step-item.completed {
    cursor: pointer;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.5rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s ease;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-check {
    font-size: 1rem;
}

.step-label {
    font-size: 0.8rem;
    color: #adb5bd;
    text-align: center;
    white-space: nowrap;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.completed:hover .step-circle {
    transform: scale(1.1);
}

