arguments.file_text:
@using sv_00e9b32308dd46098d62d300fb429c8e.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @(Index + 1)</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-outline-danger btn-sm" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Reference.Name" @bind:event="oninput" placeholder="Reference name" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship <span class="text-danger">*</span></label>
                <input class="form-control" @bind="Reference.Relationship" @bind:event="oninput" placeholder="e.g. Former Manager" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email <span class="text-danger">*</span></label>
                <input type="email" class="form-control" @bind="Reference.Email" @bind:event="oninput" placeholder="email@example.com" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone <span class="text-danger">*</span></label>
                <input type="tel" class="form-control" @bind="Reference.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ReferenceModel Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }
}

@using sv_00e9b32308dd46098d62d300fb429c8e.Models

<div>
    <h4 class="mb-3">Personal Information</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    <div class="row g-3">
        <div class="col-md-6">
            <label class="form-label">Full Name <span class="text-danger">*</span></label>
            <input class="form-control" @bind="Model.FullName" @bind:event="oninput" placeholder="John Doe" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Email <span class="text-danger">*</span></label>
            <input type="email" class="form-control @(emailError != null ? "is-invalid" : "")"
                   @bind="Model.Email" @bind:event="oninput" placeholder="john@example.com" />
            @if (emailError != null)
            {
                <div class="invalid-feedback">@emailError</div>
            }
        </div>
        <div class="col-md-6">
            <label class="form-label">Phone <span class="text-danger">*</span></label>
            <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" placeholder="(555) 123-4567" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Address <span class="text-danger">*</span></label>
            <input class="form-control" @bind="Model.Address" @bind:event="oninput" placeholder="123 Main St, City, State" />
        </div>
    </div>

    <div class="d-flex justify-content-end mt-4">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
            @if (isValidating)
            {
                <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                <span>Validating...</span>
            }
            else
            {
                <span>Next →</span>
            }
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public string? ErrorMessage { get; set; }
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public Func<string, Task<bool>>? ValidateEmail { get; set; }

    private string? emailError;
    private bool isValidating;

    private async Task HandleNext()
    {
        emailError = null;

        if (!Model.IsValid())
        {
            emailError = string.IsNullOrWhiteSpace(Model.Email) ? "Email is required." : null;
            await OnNext.InvokeAsync(); // parent will show validation error
            return;
        }

        if (ValidateEmail is not null)
        {
            isValidating = true;
            try
            {
                var isValid = await ValidateEmail(Model.Email);
                if (!isValid)
                {
                    emailError = "This email address is not valid.";
                    return;
                }
            }
            finally
            {
                isValidating = false;
            }
        }

        await OnNext.InvokeAsync();
    }
}

@using sv_00e9b32308dd46098d62d300fb429c8e.Models

<div>
    <h4 class="mb-3">Work History</h4>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="alert alert-danger">@ErrorMessage</div>
    }

    @for (var i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryCard Entry="Entries[index]"
                       Index="index"
                       ShowRemove="Entries.Count > 1"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button type="button" class="btn btn-outline-secondary mb-4" @onclick="AddEntry">
        + Add Another Position
    </button>

