arguments.file_text:
@page "/apply"
@using sv_00e9b32308dd46098d62d300fb429c8e.Models
@using sv_00e9b32308dd46098d62d300fb429c8e.Components.JobApplication
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    @if (submittedId.HasValue)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span style="font-size: 4rem;">✅</span>
            </div>
            <h3 class="text-success">Application Submitted!</h3>
            <p class="lead">Your application ID is <strong>#@submittedId</strong></p>
            <p class="text-muted">We'll be in touch soon. Thank you for applying!</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep"
                       CompletedUpTo="completedUpTo"
                       OnStepSelected="GoToStep" />

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo"
                                  ErrorMessage="@errorMessage"
                                  ValidateEmail="ValidateEmailAsync"
                                  OnNext="HandlePersonalNext" />
                break;

            case 2:
                <WorkHistoryStep Entries="workEntries"
                                 ErrorMessage="@errorMessage"
                                 OnNext="HandleWorkNext"
                                 OnBack="GoBack" />
                break;

            case 3:
                <ReferencesStep References="references"
                                ErrorMessage="@errorMessage"
                                OnNext="HandleReferencesNext"
                                OnBack="GoBack" />
                break;

            case 4:
                <CoverLetterStep @bind-CoverLetter="coverLetter"
                                 OnNext="HandleCoverLetterNext"
                                 OnBack="GoBack" />
                break;

            case 5:
                <ReviewStep Personal="personalInfo"
                            WorkEntries="workEntries"
                            References="references"
                            CoverLetter="@coverLetter"
                            IsSubmitting="isSubmitting"
                            OnBack="GoBack"
                            OnSubmit="SubmitApplication"
                            OnEditStep="GoToStep" />
                break;
        }
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private int completedUpTo = 1; // tracks highest step reached (for step indicator)
    private string? errorMessage;
    private bool isSubmitting;
    private int? submittedId;

    // Form state
    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private async Task<bool> ValidateEmailAsync(string email)
    {
        return await ApplicationService.ValidateEmailAsync(email);
    }

    private void HandlePersonalNext()
    {
        errorMessage = null;
        if (!personalInfo.IsValid())
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }
        AdvanceTo(2);
    }

    private void HandleWorkNext()
    {
        errorMessage = null;
        if (!workEntries.TrueForAll(e => e.IsValid()))
        {
            errorMessage = "Please fill in company, title, and start date for all positions.";
            return;
        }
        AdvanceTo(3);
    }

    private void HandleReferencesNext()
    {
        errorMessage = null;
        if (!references.TrueForAll(r => r.IsValid()))
        {
            errorMessage = "Please fill in all fields for each reference.";
            return;
        }
        AdvanceTo(4);
    }

    private void HandleCoverLetterNext()
    {
        errorMessage = null;
        AdvanceTo(5);
    }

    private void AdvanceTo(int step)
    {
        currentStep = step;
        if (step > completedUpTo)
            completedUpTo = step;
        errorMessage = null;
    }

    private void GoToStep(int step)
    {
        errorMessage = null;
        currentStep = step;
    }

    private void GoBack()
    {
        errorMessage = null;
        if (currentStep > 1)
            currentStep--;
    }

    private async Task SubmitApplication()
    {
        isSubmitting = true;
        errorMessage = null;

        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter
            );

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

